package hydrozoa.multisig.server

import hydrozoa.config.head.network.CardanoNetwork
import org.scalatest.funsuite.AnyFunSuite
import scala.annotation.nowarn

@nowarn("msg=unused value")
class JsonCodecTest extends AnyFunSuite {

    test("COSE signature validation works") {
        val coseKey =
            "a40101032720062158205c239cfe8c553fbd350326c6e90f77cf287d41ceaf0f73e212f6a5648482b0b8"
        val coseSignature =
            ""

        given CardanoNetwork.Section = CardanoNetwork.Preprod

        val ret = JsonCodecs.UserRequestDecoder().validateCoseSignature(coseKey, coseSignature)

        assert(ret.isRight, s"COSE signature validation failed: $ret")
        assert(
          ret.toOption.get._1.toHex == "5c239cfe8c553fbd350326c6e90f77cf287d41ceaf0f73e212f6a5648482b0b8",
          "Verification key is extracted correctly"
        )
        assert(
          ret.toOption.get._2.toHex == "",
          "Payload is extracted correctly"
        )
    }

}
